import { GameState } from '../types/index';
import { GameAction } from './actions';

// Import Handlers
import { handleRepairWork } from './reducer/repair';
import { handleSleep, handleConfirmSleep } from './reducer/sleep';
import { handleTriggerEvent, handleCloseEvent, handleToggleJournal } from './reducer/events';
import { handleAcquireItem, handlePayCost, handleBuyMarketItems, handleInstallFurnace, handleSellItem, handleUseItem, handleToggleLockItem } from './reducer/inventory';
import { handleStartCrafting, handleCancelCrafting, handleFinishCrafting, handleSetCrafting, handleUpdateForgeStatus } from './reducer/crafting';
import { handleToggleShop, handleEnqueueCustomer, handleNextCustomer, handleDismissCustomer, handleRefuseCustomer } from './reducer/shop';
import { handleAddKnownMercenary, handleScoutMercenary, handleHireMercenary, handleFireMercenary, handleAllocateStat, handleUpdateMercenaryStats, handleGiveGift, handleTalkMercenary } from './reducer/mercenary';
import { handleStartExpedition, handleCompleteExpedition, handleClaimExpedition, handleAbortExpedition, handleDismissDungeonResult } from './reducer/expedition';
import { handleEquipItem, handleUnequipItem } from './reducer/equipment';
import { handleStartManualDungeon, handleMoveManualDungeon, handleFinishManualDungeon, handleRescueNPC, handleRetreatManualDungeon, handleStartCombatManual, handleResolveCombatManual } from './reducer/manualDungeon';
import { handleTalkGarrick, handleGiftGarrick } from './reducer/market-affinity';

export const gameReducer = (state: GameState, action: GameAction): GameState => {
  switch (action.type) {
    // Save & Load
    case 'LOAD_GAME': return action.payload;

    // Repair
    case 'REPAIR_WORK': return handleRepairWork(state);

    // Sleep
    case 'SLEEP': return handleSleep(state);
    case 'CONFIRM_SLEEP': return handleConfirmSleep(state);
    case 'CLOSE_SLEEP_MODAL': return { ...state, showSleepModal: false };

    // Events
    case 'TRIGGER_EVENT': return handleTriggerEvent(state, action.payload);
    case 'CLOSE_EVENT': return handleCloseEvent(state);
    case 'TOGGLE_JOURNAL': return handleToggleJournal(state);

    // Inventory & Market
    case 'ACQUIRE_ITEM': return handleAcquireItem(state, action.payload);
    case 'PAY_COST': return handlePayCost(state, action.payload);
    case 'BUY_MARKET_ITEMS': return handleBuyMarketItems(state, action.payload);
    case 'INSTALL_FURNACE': return handleInstallFurnace(state);
    case 'SELL_ITEM': return handleSellItem(state, action.payload);
    case 'USE_ITEM': return handleUseItem(state, action.payload);
    case 'TOGGLE_LOCK_ITEM': return handleToggleLockItem(state, action.payload);

    // Crafting
    case 'START_CRAFTING': return handleStartCrafting(state, action.payload);
    case 'CANCEL_CRAFTING': return handleCancelCrafting(state, action.payload);
    case 'FINISH_CRAFTING': return handleFinishCrafting(state, action.payload);
    case 'DISMISS_CRAFTING_RESULT': return { ...state, lastCraftedItem: null };
    case 'DISMISS_TIER_UNLOCK': return { ...state, unlockedTierPopup: null };
    case 'SET_CRAFTING': return handleSetCrafting(state, action.payload);
    case 'UPDATE_FORGE_STATUS': return handleUpdateForgeStatus(state, action.payload);

    // Shop
    case 'TOGGLE_SHOP': return handleToggleShop(state);
    case 'ENQUEUE_CUSTOMER': return handleEnqueueCustomer(state, action.payload);
    case 'NEXT_CUSTOMER': return handleNextCustomer(state);
    case 'DISMISS_CUSTOMER': return handleDismissCustomer(state);
    case 'REFUSE_CUSTOMER': return handleRefuseCustomer(state, action.payload);

    // Mercenaries
    case 'ADD_KNOWN_MERCENARY': return handleAddKnownMercenary(state, action.payload);
    case 'SCOUT_MERCENARY': return handleScoutMercenary(state, action.payload);
    case 'HIRE_MERCENARY': return handleHireMercenary(state, action.payload);
    case 'FIRE_MERCENARY': return handleFireMercenary(state, action.payload);
    case 'GIVE_GIFT': return handleGiveGift(state, action.payload);
    case 'TALK_MERCENARY': return handleTalkMercenary(state, action.payload);
    case 'ALLOCATE_STAT': return handleAllocateStat(state, action.payload);
    case 'UPDATE_MERCENARY_STATS': return handleUpdateMercenaryStats(state, action.payload);

    // Garrick Market
    case 'TALK_GARRICK': return handleTalkGarrick(state);
    case 'GIFT_GARRICK': return handleGiftGarrick(state, action.payload);

    // Expedition
    case 'START_EXPEDITION': return handleStartExpedition(state, action.payload);
    case 'COMPLETE_EXPEDITION': return handleCompleteExpedition(state, action.payload);
    case 'CLAIM_EXPEDITION': return handleClaimExpedition(state, action.payload);
    case 'ABORT_EXPEDITION': return handleAbortExpedition(state, action.payload);
    case 'DISMISS_DUNGEON_RESULT': return handleDismissDungeonResult(state);

    // Equipment
    case 'EQUIP_ITEM': return handleEquipItem(state, action.payload);
    case 'UNEQUIP_ITEM': return handleUnequipItem(state, action.payload);

    // Manual Dungeon
    case 'START_MANUAL_DUNGEON': return handleStartManualDungeon(state, action.payload);
    case 'MOVE_MANUAL_DUNGEON': return handleMoveManualDungeon(state, action.payload);
    case 'FINISH_MANUAL_DUNGEON': return handleFinishManualDungeon(state);
    case 'RETREAT_MANUAL_DUNGEON': return handleRetreatManualDungeon(state);
    case 'TOGGLE_MANUAL_DUNGEON_OVERLAY': return { ...state, showManualDungeonOverlay: action.payload };
    case 'RESCUE_NPC': return handleRescueNPC(state, action.payload);
    case 'START_COMBAT_MANUAL': return handleStartCombatManual(state);
    case 'RESOLVE_COMBAT_MANUAL': return handleResolveCombatManual(state, action.payload);

    // Tutorial & Prologue
    case 'SET_TUTORIAL_STEP': return { ...state, tutorialStep: action.payload };
    case 'SET_ACTIVE_TUTORIAL_SCENE': return { ...state, activeTutorialScene: action.payload };
    case 'COMPLETE_PROLOGUE': 
        return { 
            ...state, 
            hasCompletedPrologue: true,
            activeTutorialScene: null,
            tutorialStep: 'MARKET_GUIDE' 
        };
    case 'COMPLETE_TUTORIAL':
        const finalTabs = ['FORGE', 'MARKET', 'INVENTORY', 'SHOP', 'TAVERN', 'DUNGEON', 'SIMULATION'];
        return {
            ...state,
            tutorialStep: null,
            activeTutorialScene: null,
            unlockedTabs: finalTabs,
            stats: {
                ...state.stats,
                tierLevel: Math.max(state.stats.tierLevel, 1) 
            },
            forge: { ...state.forge, hasFurnace: true }, 
            showTutorialCompleteModal: true,
            logs: ["Tutorial completed. Lockhart's Forge is fully operational.", ...state.logs]
        };
    case 'DISMISS_TUTORIAL_COMPLETE':
        return { ...state, showTutorialCompleteModal: false };

    // User Preferences
    case 'UPDATE_SETTINGS':
        return {
            ...state,
            settings: { ...state.settings, ...action.payload }
        };

    // Toast Notifications
    case 'SHOW_TOAST':
        // 현재 노출 중인 메시지와 동일하면 무시
        if (state.toast?.visible && state.toast.message === action.payload) {
            return state;
        }
        // 큐의 마지막 메시지와 동일하면 무시 (중복 쌓임 방지)
        if (state.toastQueue.length > 0 && state.toastQueue[state.toastQueue.length - 1] === action.payload) {
            return state;
        }
        return {
            ...state,
            toastQueue: [...state.toastQueue, action.payload]
        };

    case 'POP_NEXT_TOAST':
        if (state.toastQueue.length === 0) return state;
        const [nextMessage, ...remainingQueue] = state.toastQueue;
        return {
            ...state,
            toast: { message: nextMessage, visible: true },
            toastQueue: remainingQueue
        };

    case 'HIDE_TOAST':
        return {
            ...state,
            toast: state.toast ? { ...state.toast, visible: false } : null
        };

    // UI Effects
    case 'SET_UI_EFFECT':
        return {
            ...state,
            uiEffects: {
                ...state.uiEffects,
                [action.payload.effect]: action.payload.value
            }
        };

    default:
      return state;
  }
};

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { useGame } from '../../../../context/GameContext';
import { EquipmentCategory, EquipmentItem } from '../../../../types';
import { EQUIPMENT_SUBCATEGORIES, EQUIPMENT_ITEMS } from '../../../../data/equipment';
import { MASTERY_THRESHOLDS } from '../../../../config/mastery-config';
import { materials } from '../../../../data/materials';
import { getSmithingLevel, getUnlockedTier, getEnergyCost } from '../../../../utils/craftingLogic';

export const useForge = (onNavigate: (tab: any) => void) => {
  const { state, actions } = useGame();
  const { inventory, stats, isCrafting, craftingMastery, unlockedRecipes, tutorialStep, forgeTemperature, lastForgeTime } = state;
  const { hasFurnace, hasWorkbench } = state.forge;

  const [activeCategory, setActiveCategory] = useState<EquipmentCategory>('WEAPON');
  const [selectedItem, setSelectedItem] = useState<EquipmentItem | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true);
  const [isSkillsExpanded, setIsSkillsExpanded] = useState(false);
  const [expandedSubCat, setExpandedSubCat] = useState<string | null>('SWORD');
  const [favorites, setFavorites] = useState<string[]>([]);
  const [isFavExpanded, setIsFavExpanded] = useState(true);
  const [hoveredItem, setHoveredItem] = useState<EquipmentItem | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });
  const [quickCraftProgress, setQuickCraftProgress] = useState<number | null>(null);

  const smithingLevel = getSmithingLevel(stats.smithingExp);
  const workbenchLevel = getSmithingLevel(stats.workbenchExp);
  const unlockedSmithingTier = getUnlockedTier(smithingLevel);
  const unlockedWorkbenchTier = getUnlockedTier(workbenchLevel);

  const getInventoryCount = useCallback((id: string) => {
    return inventory.find(i => i.id === id)?.quantity || 0;
  }, [inventory]);

  const currentResidualTemp = useMemo(() => {
    const GLOBAL_COOLING_RATE_PER_SEC = 5;
    const timeDiffSec = (Date.now() - (lastForgeTime || 0)) / 1000;
    return Math.max(0, (forgeTemperature || 0) - (timeDiffSec * GLOBAL_COOLING_RATE_PER_SEC));
  }, [forgeTemperature, lastForgeTime]);

  const canEnterForge = useMemo(() => {
    if (!selectedItem) return false;
    if (selectedItem.craftingType === 'FORGE') {
      const hasHeat = currentResidualTemp > 0;
      const hasFuel = getInventoryCount('charcoal') > 0;
      const isTutorialForging = tutorialStep === 'START_FORGING_GUIDE';
      return hasFurnace && (hasFuel || hasHeat || isTutorialForging);
    }
    return hasWorkbench;
  }, [selectedItem, hasFurnace, hasWorkbench, currentResidualTemp, getInventoryCount, tutorialStep]);

  const requiredEnergy = useMemo(() => {
    if (!selectedItem) return 20;
    const count = craftingMastery[selectedItem.id] || 0;
    return getEnergyCost(selectedItem, count);
  }, [selectedItem, craftingMastery]);

  const visibleItems = useMemo(() => {
    return EQUIPMENT_ITEMS.filter(item => {
      const isUnlocked = item.unlockedByDefault !== false || unlockedRecipes?.includes(item.id);
      if (!isUnlocked) return false;
      const myTier = item.craftingType === 'FORGE' ? unlockedSmithingTier : unlockedWorkbenchTier;
      if (item.tier > myTier) return false;
      const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
      return subCatDef?.categoryId === activeCategory;
    });
  }, [activeCategory, unlockedSmithingTier, unlockedWorkbenchTier, unlockedRecipes]);

  const favoriteItems = useMemo(() => visibleItems.filter(item => favorites.includes(item.id)), [visibleItems, favorites]);

  const groupedItems = useMemo(() => {
    const groups: Record<string, EquipmentItem[]> = {};
    visibleItems.forEach(item => {
      if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
      groups[item.subCategoryId].push(item);
    });
    return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
    return EQUIPMENT_SUBCATEGORIES.filter(sc => 
      sc.categoryId === activeCategory && (groupedItems[sc.id]?.length || 0) > 0
    );
  }, [activeCategory, groupedItems]);

  const masteryInfo = useMemo(() => {
    if (!selectedItem) return null;
    const count = craftingMastery[selectedItem.id] || 0;
    let label = "Novice";
    let colorClass = "stroke-stone-500";
    let glowClass = "shadow-[0_0_20px_rgba(120,113,108,0.2)]";
    let progress = 0;

    if (count >= MASTERY_THRESHOLDS.ARTISAN) {
      label = "Artisan";
      colorClass = "stroke-amber-500";
      glowClass = "shadow-[0_0_40px_rgba(245,158,11,0.3)]";
      progress = Math.min(100, ((count - MASTERY_THRESHOLDS.ARTISAN) / 20) * 100);
    } else if (count >= MASTERY_THRESHOLDS.ADEPT) {
      label = "Adept";
      colorClass = "stroke-emerald-500";
      glowClass = "shadow-[0_0_30px_rgba(16,185,129,0.2)]";
      progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
    } else {
      label = "Novice";
      colorClass = "stroke-stone-400";
      glowClass = "shadow-[0_0_20px_rgba(168,162,158,0.15)]";
      progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
    }

    const radius = 46;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    return { label, colorClass, glowClass, progress, circumference, offset, count };
  }, [selectedItem, craftingMastery]);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
    setActiveCategory(cat);
    setSelectedItem(null);
    setExpandedSubCat(cat === 'WEAPON' ? 'SWORD' : 'HELMET');
  }, []);

  const startCrafting = useCallback(() => {
    if (!selectedItem) return;
    const isRequirementMet = selectedItem.craftingType === 'FORGE' ? hasFurnace : hasWorkbench;

    if (!isRequirementMet) {
      actions.triggerEvent({
        id: 'NONE',
        title: 'Installation Required',
        description: `Requires ${selectedItem.craftingType === 'FORGE' ? 'Furnace' : 'Workbench'}.`,
        options: [{ label: 'Visit Market', action: () => onNavigate('MARKET') }, { label: 'Stay here', action: () => {} }]
      });
      return;
    }

    const missing = selectedItem.requirements.filter(req => getInventoryCount(req.id) < req.count);
    if (missing.length > 0) {
      actions.showToast("Insufficient materials.");
      return;
    }

    const energyCost = getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0);
    if (stats.energy < energyCost) {
      actions.triggerEnergyHighlight();
      return;
    }

    actions.startCrafting(selectedItem);
    setIsPanelOpen(false);
  }, [selectedItem, hasFurnace, hasWorkbench, getInventoryCount, stats.energy, craftingMastery, actions, onNavigate]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) {
      actions.finishCrafting(selectedItem, score, bonus);
      if (tutorialStep === 'START_FORGING_GUIDE' && selectedItem.id === 'sword_bronze_t1') {
        actions.setTutorialStep('CRAFT_RESULT_DIALOG');
      }
    }
    setIsPanelOpen(true);
  }, [selectedItem, actions, tutorialStep]);

  const handleQuickCraft = useCallback(() => {
    if (!selectedItem) return;

    // 단계적 연료 소모치 계산 (티어 기반)
    const extraFuel = selectedItem.tier === 1 ? 3 : selectedItem.tier === 2 ? 5 : 8;
    const currentCharcoal = getInventoryCount('charcoal');

    if (currentCharcoal < extraFuel) {
        actions.showToast(`Requires ${extraFuel} additional Charcoal for Quick Craft.`);
        return;
    }

    const energyCost = getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0);
    if (stats.energy < energyCost) {
        actions.triggerEnergyHighlight();
        return;
    }

    const missingMaterials = selectedItem.requirements.filter(req => getInventoryCount(req.id) < req.count);
    if (missingMaterials.length > 0) {
      actions.showToast("Insufficient base materials.");
      return;
    }

    // 제작 프로세스 시작
    setQuickCraftProgress(0);
    const duration = 1500; // 1.5초 애니메이션
    const interval = 30;
    const step = (100 / (duration / interval));

    const timer = setInterval(() => {
      setQuickCraftProgress(prev => {
        if (prev === null || prev >= 100) {
          clearInterval(timer);

          // 자원 소모 및 아이템 생성 (품질 80 고정, 숙련도 게인 0.7 패널티)
          actions.consumeItem('charcoal', extraFuel);
          actions.startCrafting(selectedItem); // 기본 재료 및 에너지 소모
          actions.finishCrafting(selectedItem, 80, 0, 0.7);

          return null;
        }
        return prev + step;
      });
    }, interval);
  }, [selectedItem, actions, getInventoryCount, stats.energy, craftingMastery]);

  const updateTooltipPosition = (x: number, y: number) => {
    const viewportW = window.innerWidth;
    const viewportH = window.innerHeight;
    let finalX = x + 20;
    let finalY = y + 20;
    if (finalX + 240 > viewportW) finalX = x - 260;
    if (finalY + 160 > viewportH) finalY = y - 180;
    setTooltipPos({ x: finalX, y: finalY });
  };

  const handleSelectItem = useCallback((item: EquipmentItem) => {
      setSelectedItem(item);
      if (tutorialStep === 'SELECT_SWORD_GUIDE' && item.id === 'sword_bronze_t1') {
          actions.setTutorialStep('START_FORGING_GUIDE');
      }
  }, [tutorialStep, actions]);

  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      setHoveredItem(item);
      updateTooltipPosition(e.clientX, e.clientY);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) updateTooltipPosition(e.clientX, e.clientY);
  }, [hoveredItem]);

  const handleMouseLeave = useCallback(() => setHoveredItem(null), []);

  return {
    state,
    actions,
    isCrafting,
    activeCategory,
    selectedItem,
    isPanelOpen,
    isSkillsExpanded,
    expandedSubCat,
    favorites,
    isFavExpanded,
    hoveredItem,
    tooltipPos,
    quickCraftProgress,
    smithingLevel,
    workbenchLevel,
    unlockedSmithingTier,
    unlockedWorkbenchTier,
    visibleSubCats,
    groupedItems,
    favoriteItems,
    canEnterForge,
    requiredEnergy: selectedItem ? getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0) : 20,
    getInventoryCount,
    masteryInfo,
    handlers: {
      setActiveCategory,
      setSelectedItem,
      setIsPanelOpen,
      setIsSkillsExpanded,
      setExpandedSubCat,
      setFavorites,
      setIsFavExpanded,
      setHoveredItem,
      setTooltipPos,
      handleCategoryChange,
      startCrafting,
      handleMinigameComplete,
      handleQuickCraft,
      updateTooltipPosition,
      handleSelectItem,
      handleMouseEnter,
      handleMouseMove,
      handleMouseLeave,
      toggleSubCategory: (id: string) => setExpandedSubCat(prev => prev === id ? null : id),
      toggleFavorite: (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        setFavorites(prev => prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]);
      }
    }
  };
};

