  }, [selectedItem, craftingMastery]);

  const visibleItems = useMemo(() => {
    return EQUIPMENT_ITEMS.filter(item => {
      const isUnlocked = item.unlockedByDefault !== false || unlockedRecipes?.includes(item.id);
      if (!isUnlocked) return false;
      const myTier = item.craftingType === 'FORGE' ? unlockedSmithingTier : unlockedWorkbenchTier;
      if (item.tier > myTier) return false;
      const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
      return subCatDef?.categoryId === activeCategory;
    });
  }, [activeCategory, unlockedSmithingTier, unlockedWorkbenchTier, unlockedRecipes]);

  const favoriteItems = useMemo(() => visibleItems.filter(item => favorites.includes(item.id)), [visibleItems, favorites]);

  const groupedItems = useMemo(() => {
    const groups: Record<string, EquipmentItem[]> = {};
    visibleItems.forEach(item => {
      if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
      groups[item.subCategoryId].push(item);
    });
    return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
    return EQUIPMENT_SUBCATEGORIES.filter(sc => 
      sc.categoryId === activeCategory && (groupedItems[sc.id]?.length || 0) > 0
    );
  }, [activeCategory, groupedItems]);

  const masteryInfo = useMemo(() => {
    if (!selectedItem) return null;
    const count = craftingMastery[selectedItem.id] || 0;
    let label = "Novice";
    let colorClass = "stroke-stone-500";
    let glowClass = "shadow-[0_0_20px_rgba(120,113,108,0.2)]";
    let progress = 0;

    if (count >= MASTERY_THRESHOLDS.ARTISAN) {
      label = "Artisan";
      colorClass = "stroke-amber-500";
      glowClass = "shadow-[0_0_40px_rgba(245,158,11,0.3)]";
      progress = Math.min(100, ((count - MASTERY_THRESHOLDS.ARTISAN) / 20) * 100);
    } else if (count >= MASTERY_THRESHOLDS.ADEPT) {
      label = "Adept";
      colorClass = "stroke-emerald-500";
      glowClass = "shadow-[0_0_30px_rgba(16,185,129,0.2)]";
      progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
    } else {
      label = "Novice";
      colorClass = "stroke-stone-400";
      glowClass = "shadow-[0_0_20px_rgba(168,162,158,0.15)]";
      progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
    }

    const radius = 46;
    const circumference = 2 * Math.PI * radius;
    const offset = circumference - (progress / 100) * circumference;

    return { label, colorClass, glowClass, progress, circumference, offset, count };
  }, [selectedItem, craftingMastery]);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
    setActiveCategory(cat);
    setSelectedItem(null);
    setExpandedSubCat(cat === 'WEAPON' ? 'SWORD' : 'HELMET');
  }, []);

  const startCrafting = useCallback(() => {
    if (!selectedItem) return;
    const isRequirementMet = selectedItem.craftingType === 'FORGE' ? hasFurnace : hasWorkbench;

    if (!isRequirementMet) {
      actions.triggerEvent({
        id: 'NONE',
        title: 'Installation Required',
        description: `Requires ${selectedItem.craftingType === 'FORGE' ? 'Furnace' : 'Workbench'}.`,
        options: [{ label: 'Visit Market', action: () => onNavigate('MARKET') }, { label: 'Stay here', action: () => {} }]
      });
      return;
    }

    const missing = selectedItem.requirements.filter(req => getInventoryCount(req.id) < req.count);
    if (missing.length > 0) {
      actions.showToast("Insufficient materials.");
      return;
    }

    const energyCost = getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0);
    if (stats.energy < energyCost) {
      actions.triggerEnergyHighlight();
      return;
    }

    actions.startCrafting(selectedItem);
    setIsPanelOpen(false);
  }, [selectedItem, hasFurnace, hasWorkbench, getInventoryCount, stats.energy, craftingMastery, actions, onNavigate]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) {
      actions.finishCrafting(selectedItem, score, bonus);
      if (tutorialStep === 'START_FORGING_GUIDE' && selectedItem.id === 'sword_bronze_t1') {
        actions.setTutorialStep('CRAFT_RESULT_DIALOG');
      }
    }
    setIsPanelOpen(true);
  }, [selectedItem, actions, tutorialStep]);

  const handleQuickCraft = useCallback(() => {
    if (!selectedItem) return;

    // 단계적 연료 소모치 계산 (티어 및 내구도 비례 패널티 시뮬레이션)
    // 티어 1: 3개, 티어 2: 5개, 티어 3 이상: 8개
    const extraFuel = selectedItem.tier === 1 ? 3 : selectedItem.tier === 2 ? 5 : 8;
    const charcoalCount = getInventoryCount('charcoal');

    if (charcoalCount < extraFuel) {
        actions.showToast(`Quick Craft requires ${extraFuel} Charcoal.`);
        return;
    }

    const energyCost = getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0);
    if (stats.energy < energyCost) {
        actions.triggerEnergyHighlight();
        return;
    }

    const missing = selectedItem.requirements.filter(req => getInventoryCount(req.id) < req.count);
    if (missing.length > 0) {
      actions.showToast("Insufficient base materials.");
      return;
    }

    // 퀵 크래프트 시뮬레이션 프로세스
    setQuickCraftProgress(0);
    const duration = 1500; // 1.5초 고정 연출
    const interval = 30;
    const step = (100 / (duration / interval));

    const timer = setInterval(() => {
      setQuickCraftProgress(prev => {
        if (prev === null || prev >= 100) {
          clearInterval(timer);

          // 연료 소모 및 제작 완료 (품질 80 고정 = 내구도 80% 패널티 효과)
          actions.consumeItem('charcoal', extraFuel);
          actions.startCrafting(selectedItem); // 기본 재료 및 에너지 소모
          actions.finishCrafting(selectedItem, 80, 0, 0.7); // 숙련도 게인 0.7 패널티

          return null;
        }
        return prev + step;
      });
    }, interval);
  }, [selectedItem, actions, getInventoryCount, stats.energy, craftingMastery]);

  const updateTooltipPosition = (x: number, y: number) => {
    const viewportW = window.innerWidth;
    const viewportH = window.innerHeight;
    let finalX = x + 20;
    let finalY = y + 20;
    if (finalX + 240 > viewportW) finalX = x - 260;
    if (finalY + 160 > viewportH) finalY = y - 180;
    setTooltipPos({ x: finalX, y: finalY });
  };

  const handleSelectItem = useCallback((item: EquipmentItem) => {
      setSelectedItem(item);
      if (tutorialStep === 'SELECT_SWORD_GUIDE' && item.id === 'sword_bronze_t1') {
          actions.setTutorialStep('START_FORGING_GUIDE');
      }
  }, [tutorialStep, actions]);

  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      setHoveredItem(item);
      updateTooltipPosition(e.clientX, e.clientY);
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) updateTooltipPosition(e.clientX, e.clientY);
  }, [hoveredItem]);

  const handleMouseLeave = useCallback(() => setHoveredItem(null), []);

  return {
    state,
    actions,
    isCrafting,
    activeCategory,
    selectedItem,
    isPanelOpen,
    isSkillsExpanded,
    expandedSubCat,
    favorites,
    isFavExpanded,
    hoveredItem,
    tooltipPos,
    quickCraftProgress,
    smithingLevel,
    workbenchLevel,
    unlockedSmithingTier,
    unlockedWorkbenchTier,
    visibleSubCats,
    groupedItems,
    favoriteItems,
    canEnterForge,
    requiredEnergy: selectedItem ? getEnergyCost(selectedItem, craftingMastery[selectedItem.id] || 0) : 20,
    getInventoryCount,
    masteryInfo,
    handlers: {
      setActiveCategory,
      setSelectedItem,
      setIsPanelOpen,
      setIsSkillsExpanded,
      setExpandedSubCat,
      setFavorites,
      setIsFavExpanded,
      setHoveredItem,
      setTooltipPos,
      handleCategoryChange,
      startCrafting,
      handleMinigameComplete,
      handleQuickCraft,
      updateTooltipPosition,
      handleSelectItem,
      handleMouseEnter,
      handleMouseMove,
      handleMouseLeave,
      toggleSubCategory: (id: string) => setExpandedSubCat(prev => prev === id ? null : id),
      toggleFavorite: (e: React.MouseEvent, id: string) => {
        e.stopPropagation();
        setFavorites(prev => prev.includes(id) ? prev.filter(f => f !== id) : [...prev, id]);
      }
    }
  };
};

import React from 'react';
import { Hammer, Shield, Sword, ChevronRight, ChevronLeft, Lock, ChevronDown, ChevronUp, Activity, FastForward, Flame } from 'lucide-react';
import { useForge } from './hooks/useForge';
import { getAssetUrl } from '../../../utils';
import { MASTERY_THRESHOLDS } from '../../../config/mastery-config';

// Sub-components
import ForgeSkillHeader from './ui/ForgeSkillHeader';
import ForgeStatsGrid from './ui/ForgeStatsGrid';
import RecipeCard from './ui/RecipeCard';
import MasteryRadialGauge from './ui/MasteryRadialGauge';
import QuickCraftOverlay from './ui/QuickCraftOverlay';
import RecipeTooltip from './ui/RecipeTooltip';
import SmithingMinigame from './ui/SmithingMinigame';
import WorkbenchMinigame from './ui/WorkbenchMinigame';

interface ForgeTabProps {
    onNavigate: (tab: any) => void;
}

const ForgeTab: React.FC<ForgeTabProps> = ({ onNavigate }) => {
  const forge = useForge(onNavigate);
  const { state, handlers, actions, isCrafting, selectedItem, isPanelOpen, isSkillsExpanded, activeCategory, expandedSubCat, favoriteItems, isFavExpanded, visibleSubCats, groupedItems, hoveredItem, tooltipPos, quickCraftProgress, masteryInfo } = forge;

  const getItemImageUrl = (item: any) => {
    if (item.image) return getAssetUrl(item.image);
    return getAssetUrl(`${item.id}.png`);
  };

  // 퀵 크래프트 추가 연료 소모량 계산
  const getExtraFuelCost = (tier: number) => {
    if (tier === 1) return 3;
    if (tier === 2) return 5;
    return 8;
  };

  return (
    <div className="relative h-full w-full bg-stone-950 overflow-hidden" style={{ backgroundImage: `url(${getAssetUrl('tile_forge.png')})`, backgroundRepeat: 'repeat', backgroundBlendMode: 'multiply' }}>

        {isCrafting && selectedItem && (
            <div className="absolute inset-0 z-[100] bg-stone-950">
                {selectedItem.craftingType === 'FORGE' ? (
                    <SmithingMinigame 
                        onComplete={handlers.handleMinigameComplete}
                        onClose={() => actions.cancelCrafting(selectedItem)}
                        difficulty={selectedItem.tier}
                        isTutorial={state.activeTutorialScene === 'SMITHING'}
                    />
                ) : (
                    <WorkbenchMinigame 
                        onComplete={handlers.handleMinigameComplete}
                        onClose={() => actions.cancelCrafting(selectedItem)}
                        difficulty={selectedItem.tier}
                        subCategoryId={selectedItem.subCategoryId}
                        itemImage={selectedItem.image}
                    />
                )}
            </div>
        )}

        {quickCraftProgress !== null && selectedItem && (
            <QuickCraftOverlay 
                progress={quickCraftProgress} 
                extraFuel={getExtraFuelCost(selectedItem.tier)}
            />
        )}

        <div className="absolute top-2 left-2 md:top-4 md:left-4 z-20 pointer-events-auto">
            {!isSkillsExpanded ? (
                <button 
                    onClick={() => handlers.setIsSkillsExpanded(true)}
                    className="bg-stone-900/90 backdrop-blur-md border border-stone-700 rounded-full px-4 py-2 flex items-center gap-3 shadow-xl hover:bg-stone-800 transition-all group"
                >
                    <div className="flex items-center gap-1.5">
                        <Hammer className="w-3.5 h-3.5 text-amber-50" />
                        <span className="text-[10px] md:text-xs font-mono font-black text-amber-400">Lv.{forge.smithingLevel}</span>
                    </div>
                    <div className="w-px h-3 bg-stone-700" />
                    <div className="flex items-center gap-1.5">
                        <Activity className="w-3.5 h-3.5 text-stone-400" />
                        <span className="text-[10px] md:text-xs font-mono font-black text-stone-300">Lv.{forge.workbenchLevel}</span>
                    </div>
                    <ChevronDown className="w-3 h-3 text-stone-500 group-hover:text-amber-500 transition-colors" />
                </button>
            ) : (
                <div className="flex flex-col gap-2">
                    <button onClick={() => handlers.setIsSkillsExpanded(false)} className="self-start mb-1 bg-stone-900/80 border border-stone-700 px-3 py-1 rounded-full text-[8px] font-black text-stone-400 hover:text-white uppercase tracking-widest flex items-center gap-1 shadow-lg transition-all"><ChevronUp className="w-3 h-3" /> Hide Progress</button>
                    <ForgeSkillHeader exp={state.stats.smithingExp} label="Smithing" icon={Hammer} />
                    <ForgeSkillHeader exp={state.stats.workbenchExp} label="Workbench" icon={Activity} />
                </div>
            )}
        </div>

        <div className="absolute inset-0 z-0 flex w-full h-full">
            <div className={`h-full relative flex flex-col transition-all duration-500 ease-in-out ${isPanelOpen ? 'w-[55%] md:w-[60%]' : 'w-full'}`}>
                <div className="w-full h-full flex flex-col items-center justify-center p-4 md:p-8 bg-stone-925/40 relative overflow-hidden text-center">
                    {selectedItem ? (
                        <div className="z-10 flex flex-col items-center animate-in fade-in zoom-in duration-300 w-full max-w-lg mx-auto">
                            <MasteryRadialGauge imageUrl={getItemImageUrl(selectedItem)} masteryInfo={masteryInfo} />
                            <h2 className="text-xl md:text-3xl font-bold text-amber-500 mb-1.5 font-serif tracking-wide">{selectedItem.name}</h2>
                            <p className="text-stone-500 mb-6 italic text-[9px] md:text-sm px-6">"{selectedItem.description}"</p>
                            <ForgeStatsGrid item={selectedItem} />

                            <div className="flex flex-col sm:flex-row gap-3 w-full items-center justify-center px-4">
                                <button 
                                    onClick={handlers.startCrafting} 
                                    data-tutorial-id="START_FORGING_BUTTON"
                                    className={`w-full max-w-[200px] h-14 md:h-20 rounded-lg font-black text-sm md:text-base shadow-lg transition-all flex items-center justify-center gap-3 border ${forge.canEnterForge ? (selectedItem.craftingType === 'FORGE' ? 'bg-amber-700 hover:bg-amber-600 border-amber-500' : 'bg-emerald-700 hover:bg-emerald-600 border-emerald-500') : 'bg-stone-800 text-stone-500 border-stone-700 grayscale opacity-70'}`}
                                >
                                    <Hammer className="w-4 h-4 md:w-6 md:h-6" />
                                    <span>Start Forging</span>
                                </button>

                                {/* Quick Craft Button - Unlocked after 1 craft for testing */}
                                {(state.craftingMastery[selectedItem.id] || 0) >= 1 && (
                                    <button 
